var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>A-17 구역, D-03 구역 통신 두절!</color>","JPN":"<color=#ffd34c>A-17区域、D-03区域からの通信が途絶！</color>","ENG":"<color=#ffd34c>Areas A-17 and D-03, communication lost!</color>","TWN":"<color=#ffd34c>A-17區域，D-03區域通訊中斷！</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>보관 중인 아티팩트는 전부 소각해!</color>","JPN":"<color=#ffd34c>保管しているアーティファクトは全部焼却しろ！</color>","ENG":"<color=#ffd34c>Burn all the Artifacts we have on board!</color>","TWN":"<color=#ffd34c>保管中的人造神器全部燒毀！</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>오, 오지 마! 오지 마아아아!</color>","JPN":"<color=#ffd34c>く、来るな！　来るなあああ！</color>","ENG":"<color=#ffd34c>S-stay back! GET AWAAAAY!</color>","TWN":"<color=#ffd34c>別…別過來！別過來啊啊！</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그림자들의 정신 공격에 대응할 수가 없습니다! 카운터들까지 아군을…… 커헉!</color>","JPN":"<color=#ffd34c>シャドウの精神攻撃に対応できません！　カウンターまで味方を……がはっ！</color>","ENG":"<color=#ffd34c>There is nothing we can do about the Shadows' psychological attacks! Even the Counters are attacking our– Kuh!!</color>","TWN":"<color=#ffd34c>對付不了暗影的精神攻擊！連制裁者都在殘殺我方……咳啊！</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"……기관장님과 통신 연결하도록.","JPN":"……機関長へ通信を繋げろ。","ENG":"...Connect me to Chief.","TWN":"……聯絡機關長。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"으, 으으……","JPN":"う、うう……","ENG":"U-ugh...","TWN":"呃…呃呃……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"명령이 안 들리나! 기관장님과 연결해! 어서!","JPN":"命令が聞こえないのか！　機関長だ！　早く！","ENG":"Did you not hear me?! Connect me to Chief, NOW!","TWN":"沒聽見我的命令嗎！聯絡機關長！快點！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"아, 알겠습니다!!","JPN":"りょ、了解しました！！","ENG":"Y-yes, sir!!","TWN":"好…好的！！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기다리고 있었어요. 전략 위성을 통해 상황은 파악했습니다.","JPN":"待っていましたわ。戦略衛星を通じて状況は把握しています。","ENG":"I've been waiting for you to call. I saw what happened through the satellite.","TWN":"我正在等你的電話。情況我已經通過戰略衛星了解到了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"죄송합니다, 기관장님. 저희의 예상 이상으로 적의 전력이 우위에 있었습니다.","JPN":"申し訳ございません、機関長。我々の予想以上に、敵の戦力が優勢でした。","ENG":"My apologies, Chief. The enemy forces were far superior to our expectations.","TWN":"對不起，機關長。敵人的戰鬥力超出了我們的預料。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"네. 최선을 다했다는 사실은 저도 알고 있답니다.","JPN":"はい。全力で戦ったということは私も知っています。","ENG":"Yes, and I know you did your best.","TWN":"是的，我也知道你們已經盡力了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"사실대로 말씀드리죠. 저희 전력으로는 모든 봉인 시설을 완벽하게 방어할 수 없습니다.","JPN":"ありのままにお話ししましょう。私たちの戦力では、すべての隔離施設を完璧に防御することはできません。","ENG":"I'll be honest with you. With our limited resources, we are unable to fully defend all quarantine facilities.","TWN":"說實話，憑我們的戰鬥力，根本沒辦法守住所有隔離設施。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"어느 정도는 각오했던 상황이었어요.","JPN":"ある程度は覚悟していた状況です。","ENG":"This much, I had expected.","TWN":"在某種程度上，我已經做好了心理準備。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신도 함께 퇴거하라고 지시한들…… 명령에 따르지 않겠죠.","JPN":"あなたに一緒に退却するよう指示しても……命令に従わないでしょう。","ENG":"But even if I had ordered you to retreat, I'm sure you would have refused.","TWN":"就算我下令讓你一起撤退……你應該也不會聽吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"가출했으니 모른 척 해 달라는 지시만 안 내리셨어도 고민했을 텐데 말입니다.","JPN":"家出をしたから知らないふりをしてくれ、というご指示さえなければ悩んではみたはずですが。","ENG":"I would've considered it if you hadn't ordered me to turn a blind eye to your running away from home.","TWN":"如果你沒下達“我離家出走了，你就假裝不知道”的指示，我應該會很苦惱。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"저 광신도들에게 무덤을 만들어 줄 기회입니다. 놓칠 수 없죠.","JPN":"あの狂信徒たちに墓を作ってやるチャンスです。逃すわけにはいきません。","ENG":"I cannot let this chance to bury those fanatics pass me by.","TWN":"這是給那些狂信徒挖墳墓的機會，我是不會錯過的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};